import React, { useState, useEffect } from 'react';
import {
  Box,
  Container,
  Typography,
  TextField,
  Button,
  Paper,
  Grid,
  Card,
  CardContent,
  Divider,
  CircularProgress,
  Alert,
  IconButton,
  Tooltip,
  Fade,
  Chip,
  Avatar,
  Stepper,
  Step,
  StepLabel
} from '@mui/material';
import ContentCopyIcon from '@mui/icons-material/ContentCopy';
import EditIcon from '@mui/icons-material/Edit';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import AutoAwesomeIcon from '@mui/icons-material/AutoAwesome';
import SendIcon from '@mui/icons-material/Send';
import DownloadIcon from '@mui/icons-material/Download';
import ShareIcon from '@mui/icons-material/Share';
import { useTheme } from '@mui/material/styles';

const EnhancePage = () => {
  const theme = useTheme();
  const [originalText, setOriginalText] = useState('');
  const [enhancedText, setEnhancedText] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isComplete, setIsComplete] = useState(false);
  const [approvalLink, setApprovalLink] = useState('');
  const [copied, setCopied] = useState(false);
  const [activeStep, setActiveStep] = useState(0);

  // Example industries for the dropdown
  const industries = [
    "Coaching",
    "Consulting",
    "Web Design",
    "Marketing",
    "Fitness",
    "Education",
    "E-commerce",
    "Real Estate"
  ];

  const steps = [
    'Enter testimonial',
    'Review enhancement',
    'Share & verify'
  ];

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!originalText.trim()) return;

    setIsProcessing(true);

    // Simulate API call to AI enhancement service
    setTimeout(() => {
      const enhanced = "Working with this coach transformed how I approach challenges. Their methods didn't just provide temporary solutions—they fundamentally changed my perspective. I went from feeling overwhelmed to confident and accomplished, with measurable results in just weeks.";
      setEnhancedText(enhanced);
      setIsProcessing(false);
      setIsComplete(true);
      setApprovalLink(`https://testy.app/verify/${Math.random().toString(36).substring(2, 15)}`);
      setActiveStep(1);
    }, 2000);
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(approvalLink);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSendForApproval = () => {
    // In a real app, this would send an email or notification
    setActiveStep(2);
  };

  return (
    <Container maxWidth="md" sx={{ py: 6 }}>
      <Box sx={{ mb: 6 }}>
        <Stepper activeStep={activeStep} alternativeLabel>
          {steps.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>
      </Box>

      <Typography variant="h2" align="center" gutterBottom>
        Enhance Your Testimonial
      </Typography>
      <Typography variant="subtitle1" align="center" color="text.secondary" sx={{ mb: 6 }}>
        Transform client feedback into compelling stories that showcase your true impact
      </Typography>

      {!isComplete ? (
        <Fade in={!isComplete}>
          <Card 
            elevation={0} 
            sx={{ 
              p: 4, 
              borderRadius: 3,
              border: '1px solid rgba(0, 0, 0, 0.08)',
              background: 'linear-gradient(to bottom, #ffffff, #f8fafc)'
            }}
          >
            <form onSubmit={handleSubmit}>
              <Grid container spacing={3}>
                <Grid item xs={12}>
                  <Typography variant="h6" gutterBottom>
                    Paste your client's original testimonial
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                    Even if it's brief or bland, our AI will extract the value and impact
                  </Typography>
                  <TextField
                    multiline
                    rows={6}
                    fullWidth
                    variant="outlined"
                    value={originalText}
                    onChange={(e) => setOriginalText(e.target.value)}
                    placeholder="Example: The coaching was good. I learned some things that helped me."
                    sx={{ mb: 3 }}
                  />
                </Grid>

                <Grid item xs={12} sm={6}>
                  <Typography variant="body2" gutterBottom>
                    Industry (optional)
                  </Typography>
                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 1 }}>
                    {industries.slice(0, 5).map((industry) => (
                      <Chip 
                        key={industry} 
                        label={industry} 
                        onClick={() => {}} 
                        sx={{ 
                          borderRadius: 2,
                          '&:hover': { bgcolor: 'primary.light', color: 'primary.dark' }
                        }} 
                      />
                    ))}
                  </Box>
                </Grid>

                <Grid item xs={12} sm={6}>
                  <Typography variant="body2" gutterBottom>
                    Client name (optional)
                  </Typography>
                  <TextField
                    fullWidth
                    variant="outlined"
                    placeholder="John D."
                    size="small"
                  />
                </Grid>

                <Grid item xs={12} sx={{ mt: 2 }}>
                  <Button
                    type="submit"
                    variant="contained"
                    color="primary"
                    size="large"
                    fullWidth
                    disabled={!originalText.trim() || isProcessing}
                    startIcon={isProcessing ? <CircularProgress size={20} color="inherit" /> : <AutoAwesomeIcon />}
                    sx={{ py: 1.5 }}
                  >
                    {isProcessing ? 'Enhancing...' : 'Enhance Testimonial'}
                  </Button>
                </Grid>
              </Grid>
            </form>
          </Card>
        </Fade>
      ) : (
        <Fade in={isComplete}>
          <Box>
            {/* Enhancement Preview */}
            <Card 
              elevation={0} 
              sx={{ 
                mb: 4,
                borderRadius: 3,
                border: '1px solid rgba(0, 0, 0, 0.08)',
                overflow: 'hidden'
              }}
            >
              <Grid container>
                <Grid item xs={12} md={5} sx={{ 
                  bgcolor: 'grey.50', 
                  p: 4,
                  borderRight: { md: '1px dashed rgba(0, 0, 0, 0.1)' },
                  borderBottom: { xs: '1px dashed rgba(0, 0, 0, 0.1)', md: 'none' }
                }}>
                  <Typography variant="overline" color="text.secondary" sx={{ fontWeight: 600 }}>
                    ORIGINAL
                  </Typography>
                  <Typography variant="body1" sx={{ mt: 2 }}>
                    {originalText}
                  </Typography>
                </Grid>

                <Grid item xs={12} md={7} sx={{ 
                  p: 4,
                  bgcolor: 'primary.light',
                  position: 'relative',
                  overflow: 'hidden'
                }}>
                  <Box 
                    sx={{
                      position: 'absolute',
                      top: 0,
                      right: 0,
                      p: 2
                    }}
                  >
                    <Chip 
                      icon={<AutoAwesomeIcon />} 
                      label="AI Enhanced" 
                      size="small"
                      sx={{ 
                        bgcolor: 'white',
                        color: 'primary.main',
                        fontWeight: 600
                      }}
                    />
                  </Box>

                  <Typography variant="overline" color="primary.dark" sx={{ fontWeight: 600 }}>
                    ENHANCED
                  </Typography>
                  <Typography variant="body1" sx={{ mt: 2, color: 'primary.dark', fontWeight: 500 }}>
                    {enhancedText}
                  </Typography>

                  <Box sx={{ mt: 3, display: 'flex', gap: 2 }}>
                    <Button 
                      variant="contained"
                      size="small"
                      sx={{ 
                        bgcolor: 'white', 
                        color: 'primary.main',
                        '&:hover': { bgcolor: 'rgba(255, 255, 255, 0.9)' }
                      }}
                      onClick={() => setActiveStep(0)}
                      startIcon={<EditIcon />}
                    >
                      Edit
                    </Button>

                    <Button 
                      variant="contained"
                      size="small"
                      color="primary"
                      sx={{ 
                        bgcolor: 'primary.dark',
                        '&:hover': { bgcolor: 'primary.dark', opacity: 0.9 }
                      }}
                      onClick={handleSendForApproval}
                      startIcon={<SendIcon />}
                    >
                      Send for Approval
                    </Button>
                  </Box>
                </Grid>
              </Grid>
            </Card>

            {/* Approval Link Section */}
            {activeStep === 2 && (
              <Fade in={activeStep === 2}>
                <Card 
                  elevation={0} 
                  sx={{ 
                    p: 4, 
                    borderRadius: 3,
                    border: '1px solid rgba(0, 0, 0, 0.08)',
                    background: 'linear-gradient(to bottom, #ffffff, #f8fafc)'
                  }}
                >
                  <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
                    <CheckCircleIcon sx={{ color: 'success.main', mr: 1.5, fontSize: 28 }} />
                    <Typography variant="h5">
                      Approval Link Created
                    </Typography>
                  </Box>

                  <Typography variant="body1" sx={{ mb: 3 }}>
                    Share this link with your client to verify this enhanced testimonial:
                  </Typography>

                  <Box 
                    sx={{ 
                      display: 'flex', 
                      alignItems: 'center',
                      p: 2,
                      borderRadius: 2,
                      border: '1px solid rgba(0, 0, 0, 0.1)',
                      bgcolor: 'white',
                      mb: 3
                    }}
                  >
                    <Typography 
                      variant="body2" 
                      sx={{ 
                        flexGrow: 1,
                        overflow: 'hidden',
                        textOverflow: 'ellipsis',
                        whiteSpace: 'nowrap',
                        fontFamily: 'monospace',
                        color: 'text.secondary'
                      }}
                    >
                      {approvalLink}
                    </Typography>
                    <Button 
                      variant="contained"
                      size="small"
                      onClick={handleCopy}
                      startIcon={copied ? <CheckCircleIcon /> : <ContentCopyIcon />}
                      sx={{ ml: 2 }}
                    >
                      {copied ? 'Copied!' : 'Copy Link'}
                    </Button>
                  </Box>

                  <Alert 
                    severity="info" 
                    sx={{ 
                      mb: 4, 
                      borderRadius: 2,
                      '& .MuiAlert-icon': { alignItems: 'center' }
                    }}
                  >
                    Your client will see both versions and can approve with one click. No account needed.
                  </Alert>

                  <Divider sx={{ my: 3 }} />

                  <Typography variant="h6" gutterBottom>
                    Export Options
                  </Typography>

                  <Box sx={{ display: 'flex', justifyContent: 'flex-start', gap: 2, flexWrap: 'wrap' }}>
                    <Button 
                      variant="outlined" 
                      color="primary"
                      startIcon={<DownloadIcon />}
                    >
                      Download as Image
                    </Button>
                    <Button 
                      variant="outlined"
                      color="primary"
                      startIcon={<ContentCopyIcon />}
                    >
                      Copy HTML
                    </Button>
                    <Button 
                      variant="outlined"
                      color="primary"
                      startIcon={<ShareIcon />}
                    >
                      Share
                    </Button>
                  </Box>
                </Card>
              </Fade>
            )}
          </Box>
        </Fade>
      )}
    </Container>
  );
};

export default EnhancePage;
